     1→import { 
     2→  IssueLabel, 
     3→  IssueLabelConnection,
     4→  Issue,
     5→  IssueConnection,
     6→  LinearDocument
     7→} from '@linear/sdk';
     8→
     9→type LabelCreateInput = LinearDocument.IssueLabelCreateInput;
    10→type LabelUpdateInput = LinearDocument.IssueLabelUpdateInput;
    11→type LinearLabelFilter = LinearDocument.IssueLabelFilter;
    12→type LinearIssueFilter = LinearDocument.IssueFilter;
    13→
    14→import { linearClient } from '@atoms/client/linear-client';
    15→import { logger } from '@atoms/shared/logger';
    16→import { 
    17→  NotFoundError, 
    18→  ValidationError, 
    19→  BatchOperationResult,
    20→  Pagination 
    21→} from '@atoms/types/common';
    22→import { 
    23→  LabelCreate, 
    24→  LabelUpdate, 
    25→  LabelFilter,
    26→  LabelCreateSchema,
    27→  LabelUpdateSchema,
    28→  BulkLabelOperation,
    29→  BulkLabelOperationSchema
    30→} from './schemas';
    31→
    32→export class LabelService {
    33→  private client = linearClient.getClient();
    34→
    35→  async create(data: LabelCreate): Promise<IssueLabel> {
    36→    try {
    37→      // Validate input
    38→      const validatedData = LabelCreateSchema.parse(data);
    39→      
    40→      logger.debug('Creating label', validatedData);
    41→      
    42→      const input: LabelCreateInput = {
    43→        name: validatedData.name,
    44→        color: validatedData.color,
    45→        description: validatedData.description,
    46→        teamId: validatedData.teamId,
    47→        parentId: validatedData.parentId,
    48→      };
    49→
    50→      const payload = await this.client.createIssueLabel(input);
    51→      
    52→      if (!payload.success || !payload.issueLabel) {
    53→        throw new ValidationError('Failed to create label');
    54→      }
    55→
    56→      const label = await payload.issueLabel;
    57→      logger.success(`Label created: ${label.name}`);
    58→      
    59→      return label;
    60→    } catch (error) {
    61→      if (error instanceof ValidationError) {
    62→        throw error;
    63→      }
    64→      logger.error('Failed to create label', error);
    65→      throw error;
    66→    }
    67→  }
    68→
    69→  async get(id: string): Promise<IssueLabel | null> {
    70→    try {
    71→      logger.debug(`Fetching label: ${id}`);
    72→      const label = await this.client.issueLabel(id);
    73→      return label;
    74→    } catch (error) {
    75→      logger.debug(`Label not found: ${id}`);
    76→      return null;
    77→    }
    78→  }
    79→
    80→  async getByName(name: string, teamId?: string): Promise<IssueLabel | null> {
    81→    try {
    82→      logger.debug(`Fetching label by name: ${name}`, { teamId });
    83→      
    84→      const filter: any = {
    85→        name: { eq: name },
    86→      };
    87→
    88→      if (teamId === undefined) {
    89→        // Workspace label - no team filter
    90→        filter.team = null;
    91→      } else {
    92→        // Team-specific label
    93→        filter.team = { id: { eq: teamId } };
    94→      }
    95→
    96→      const labels = await this.client.issueLabels({
    97→        filter,
    98→        first: 1
    99→      });
   100→
   101→      const nodes = await labels.nodes;
   102→      return nodes.length > 0 ? nodes[0] : null;
   103→    } catch (error) {
   104→      logger.debug(`Label not found: ${name}`);
   105→      return null;
   106→    }
   107→  }
   108→
   109→  async update(id: string, data: LabelUpdate): Promise<IssueLabel> {
   110→    try {
   111→      // Validate input
   112→      const validatedData = LabelUpdateSchema.parse(data);
   113→      
   114→      logger.debug(`Updating label: ${id}`, validatedData);
   115→      
   116→      const label = await this.get(id);
   117→      if (!label) {
   118→        throw new NotFoundError('Label', id);
   119→      }
   120→
   121→      const input: LabelUpdateInput = {
   122→        name: validatedData.name,
   123→        color: validatedData.color,
   124→        description: validatedData.description,
   125→      };
   126→
   127→      const payload = await this.client.updateIssueLabel(id, input);
   128→      
   129→      if (!payload.success || !payload.issueLabel) {
   130→        throw new ValidationError('Failed to update label');
   131→      }
   132→
   133→      const updatedLabel = await payload.issueLabel;
   134→      logger.success(`Label updated: ${updatedLabel.name}`);
   135→      
   136→      return updatedLabel;
   137→    } catch (error) {
   138→      if (error instanceof NotFoundError || error instanceof ValidationError) {
   139→        throw error;
   140→      }
   141→      logger.error(`Failed to update label ${id}`, error);
   142→      throw error;
   143→    }
   144→  }
   145→
   146→  async delete(id: string): Promise<boolean> {
   147→    try {
   148→      logger.debug(`Deleting label: ${id}`);
   149→      
   150→      const label = await this.get(id);
   151→      if (!label) {
   152→        throw new NotFoundError('Label', id);
   153→      }
   154→
   155→      const payload = await this.client.deleteIssueLabel(id);
   156→      
   157→      if (!payload.success) {
   158→        throw new ValidationError('Failed to delete label');
   159→      }
   160→
   161→      logger.success(`Label deleted: ${id}`);
   162→      return true;
   163→    } catch (error) {
   164→      if (error instanceof NotFoundError) {
   165→        throw error;
   166→      }
   167→      logger.error(`Failed to delete label ${id}`, error);
   168→      throw error;
   169→    }
   170→  }
   171→
   172→  async list(filter?: LabelFilter, pagination?: Pagination): Promise<IssueLabelConnection> {
   173→    try {
   174→      logger.debug('Listing labels', { filter, pagination });
   175→      
   176→      const linearFilter: LinearLabelFilter = {};
   177→      
   178→      if (filter) {
   179→        if (filter.teamId === null) {
   180→          // Workspace labels only
   181→          linearFilter.team = null;
   182→        } else if (filter.teamId) {
   183→          // Team-specific labels
   184→          linearFilter.team = { id: { eq: filter.teamId } };
   185→        }
   186→        
   187→        if (filter.searchQuery) {
   188→          linearFilter.name = { contains: filter.searchQuery };
   189→        }
   190→      }
   191→
   192→      const labels = await this.client.issueLabels({
   193→        filter: linearFilter,
   194→        includeArchived: filter?.includeArchived,
   195→        first: pagination?.first,
   196→        after: pagination?.after,
   197→        before: pagination?.before,
   198→        last: pagination?.last,
   199→      });
   200→
   201→      return labels;
   202→    } catch (error) {
   203→      logger.error('Failed to list labels', error);
   204→      throw error;
   205→    }
   206→  }
   207→
   208→  async listByTeam(teamId: string): Promise<IssueLabelConnection> {
   209→    try {
   210→      logger.debug(`Listing labels for team: ${teamId}`);
   211→      
   212→      const labels = await this.client.issueLabels({
   213→        filter: {
   214→          team: { id: { eq: teamId } },
   215→        },
   216→        includeArchived: false,
   217→      });
   218→
   219→      return labels;
   220→    } catch (error) {
   221→      logger.error(`Failed to list labels for team ${teamId}`, error);
   222→      throw error;
   223→    }
   224→  }
   225→
   226→  async addToIssue(issueId: string, labelId: string): Promise<Issue> {
   227→    try {
   228→      logger.debug(`Adding label ${labelId} to issue ${issueId}`);
   229→      
   230→      const issue = await this.client.issue(issueId);
   231→      if (!issue) {
   232→        throw new NotFoundError('Issue', issueId);
   233→      }
   234→
   235→      const currentLabelIds = (await issue.labels()).nodes.map(l => l.id);
   236→      const newLabelIds = [...new Set([...currentLabelIds, labelId])];
   237→
   238→      const payload = await this.client.updateIssue(issueId, {
   239→        labelIds: newLabelIds,
   240→      });
   241→
   242→      if (!payload.success || !payload.issue) {
   243→        throw new ValidationError('Failed to add label to issue');
   244→      }
   245→
   246→      const updatedIssue = await payload.issue;
   247→      logger.success(`Label added to issue ${issueId}`);
   248→      
   249→      return updatedIssue;
   250→    } catch (error) {
   251→      if (error instanceof NotFoundError) {
   252→        throw error;
   253→      }
   254→      logger.error(`Failed to add label to issue ${issueId}`, error);
   255→      throw error;
   256→    }
   257→  }
   258→
   259→  async removeFromIssue(issueId: string, labelId: string): Promise<Issue> {
   260→    try {
   261→      logger.debug(`Removing label ${labelId} from issue ${issueId}`);
   262→      
   263→      const issue = await this.client.issue(issueId);
   264→      if (!issue) {
   265→        throw new NotFoundError('Issue', issueId);
   266→      }
   267→
   268→      const currentLabelIds = (await issue.labels()).nodes.map(l => l.id);
   269→      const newLabelIds = currentLabelIds.filter(id => id !== labelId);
   270→
   271→      const payload = await this.client.updateIssue(issueId, {
   272→        labelIds: newLabelIds,
   273→      });
   274→
   275→      if (!payload.success || !payload.issue) {
   276→        throw new ValidationError('Failed to remove label from issue');
   277→      }
