     1→import { 
     2→  Cycle, 
     3→  CycleConnection,
     4→  Issue,
     5→  IssueConnection,
     6→  LinearDocument
     7→} from '@linear/sdk';
     8→
     9→type CycleCreateInput = LinearDocument.CycleCreateInput;
    10→type CycleUpdateInput = LinearDocument.CycleUpdateInput;
    11→type LinearCycleFilter = LinearDocument.CycleFilter;
    12→type LinearIssueFilter = LinearDocument.IssueFilter;
    13→
    14→import { linearClient } from '@atoms/client/linear-client';
    15→import { logger } from '@atoms/shared/logger';
    16→import { 
    17→  NotFoundError, 
    18→  ValidationError,
    19→  Pagination 
    20→} from '@atoms/types/common';
    21→import { 
    22→  CycleCreate, 
    23→  CycleUpdate, 
    24→  CycleFilter,
    25→  CycleProgress
    26→} from './schemas';
    27→import { IssueFilter } from '@features/issue/schemas';
    28→
    29→export class CycleService {
    30→  private client = linearClient.getClient();
    31→
    32→  async create(data: CycleCreate): Promise<Cycle> {
    33→    try {
    34→      logger.debug('Creating cycle', data);
    35→      
    36→      // Check for overlapping cycles within the same team
    37→      await this.validateNonOverlapping(data.teamId, data.startsAt, data.endsAt);
    38→      
    39→      const input: CycleCreateInput = {
    40→        name: data.name,
    41→        teamId: data.teamId,
    42→        startsAt: new Date(data.startsAt),
    43→        endsAt: new Date(data.endsAt),
    44→        description: data.description,
    45→      };
    46→
    47→      const payload = await this.client.createCycle(input);
    48→      
    49→      if (!payload.success || !payload.cycle) {
    50→        throw new ValidationError('Failed to create cycle');
    51→      }
    52→
    53→      const cycle = await payload.cycle;
    54→      logger.success(`Cycle created: ${cycle.name}`);
    55→      
    56→      return cycle;
    57→    } catch (error) {
    58→      logger.error('Failed to create cycle', error);
    59→      throw error;
    60→    }
    61→  }
    62→
    63→  async get(id: string): Promise<Cycle | null> {
    64→    try {
    65→      logger.debug(`Fetching cycle: ${id}`);
    66→      const cycle = await this.client.cycle(id);
    67→      return cycle;
    68→    } catch (error) {
    69→      logger.debug(`Cycle not found: ${id}`);
    70→      return null;
    71→    }
    72→  }
    73→
    74→  async update(id: string, data: CycleUpdate): Promise<Cycle> {
    75→    try {
    76→      logger.debug(`Updating cycle: ${id}`, data);
    77→      
    78→      const cycle = await this.get(id);
    79→      if (!cycle) {
    80→        throw new NotFoundError('Cycle', id);
    81→      }
    82→
    83→      // If updating dates, check for overlapping cycles
    84→      if (data.startsAt || data.endsAt) {
    85→        const startDate = data.startsAt || cycle.startsAt.toISOString();
    86→        const endDate = data.endsAt || cycle.endsAt.toISOString();
    87→        const team = await cycle.team();
    88→        
    89→        await this.validateNonOverlapping(team.id, startDate, endDate, id);
    90→      }
    91→
    92→      const input: CycleUpdateInput = {
    93→        name: data.name,
    94→        description: data.description,
    95→        startsAt: data.startsAt ? new Date(data.startsAt) : undefined,
    96→        endsAt: data.endsAt ? new Date(data.endsAt) : undefined,
    97→      };
    98→
    99→      const payload = await this.client.updateCycle(id, input);
   100→      
   101→      if (!payload.success || !payload.cycle) {
   102→        throw new ValidationError('Failed to update cycle');
   103→      }
   104→
   105→      const updatedCycle = await payload.cycle;
   106→      logger.success(`Cycle updated: ${updatedCycle.name}`);
   107→      
   108→      return updatedCycle;
   109→    } catch (error) {
   110→      logger.error(`Failed to update cycle ${id}`, error);
   111→      throw error;
   112→    }
   113→  }
   114→
   115→  async archive(id: string): Promise<boolean> {
   116→    try {
   117→      logger.debug(`Archiving cycle: ${id}`);
   118→      
   119→      const cycle = await this.get(id);
   120→      if (!cycle) {
   121→        throw new NotFoundError('Cycle', id);
   122→      }
   123→
   124→      const payload = await this.client.archiveCycle(id);
   125→      
   126→      if (!payload.success) {
   127→        throw new ValidationError('Failed to archive cycle');
   128→      }
   129→
   130→      logger.success(`Cycle archived: ${id}`);
   131→      return true;
   132→    } catch (error) {
   133→      logger.error(`Failed to archive cycle ${id}`, error);
   134→      throw error;
   135→    }
   136→  }
   137→
   138→  async list(filter?: CycleFilter, pagination?: Pagination): Promise<CycleConnection> {
   139→    try {
   140→      logger.debug('Listing cycles', { filter, pagination });
   141→      
   142→      const linearFilter: LinearCycleFilter = {};
   143→      
   144→      if (filter) {
   145→        if (filter.teamId) {
   146→          linearFilter.team = { id: { eq: filter.teamId } };
   147→        }
   148→      }
   149→
   150→      const cycles = await this.client.cycles({
   151→        filter: linearFilter,
   152→        includeArchived: filter?.includeArchived,
   153→        first: pagination?.first,
   154→        after: pagination?.after,
   155→        before: pagination?.before,
   156→        last: pagination?.last,
   157→      });
   158→
   159→      return cycles;
   160→    } catch (error) {
   161→      logger.error('Failed to list cycles', error);
   162→      throw error;
   163→    }
   164→  }
   165→
   166→  async getActive(teamId: string): Promise<Cycle | null> {
   167→    try {
   168→      logger.debug(`Getting active cycle for team: ${teamId}`);
   169→      
   170→      const cycles = await this.client.cycles({
   171→        filter: {
   172→          team: { id: { eq: teamId } },
   173→        },
   174→        includeArchived: false,
   175→      });
   176→
   177→      const cycleNodes = await cycles.nodes;
   178→      const now = new Date();
   179→      
   180→      // Find cycle where current time is between start and end dates
   181→      const activeCycle = cycleNodes.find(cycle => {
   182→        const startDate = new Date(cycle.startsAt);
   183→        const endDate = new Date(cycle.endsAt);
   184→        return now >= startDate && now <= endDate;
   185→      });
   186→
   187→      return activeCycle || null;
   188→    } catch (error) {
   189→      logger.error(`Failed to get active cycle for team ${teamId}`, error);
   190→      throw error;
   191→    }
   192→  }
   193→
   194→  async getUpcoming(teamId: string): Promise<CycleConnection> {
   195→    try {
   196→      logger.debug(`Getting upcoming cycles for team: ${teamId}`);
   197→      
   198→      const cycles = await this.client.cycles({
   199→        filter: {
   200→          team: { id: { eq: teamId } },
   201→        },
   202→        includeArchived: false,
   203→      });
   204→
   205→      const cycleNodes = await cycles.nodes;
   206→      const now = new Date();
   207→      
   208→      // Filter cycles that start in the future
   209→      const upcomingCycles = cycleNodes.filter(cycle => {
   210→        const startDate = new Date(cycle.startsAt);
   211→        return startDate > now;
   212→      });
   213→
   214→      // Return as connection format (simplified mock for now)
   215→      return {
   216→        ...cycles,
   217→        nodes: upcomingCycles,
   218→      } as CycleConnection;
   219→    } catch (error) {
   220→      logger.error(`Failed to get upcoming cycles for team ${teamId}`, error);
   221→      throw error;
   222→    }
   223→  }
   224→
   225→  async getCompleted(teamId: string): Promise<CycleConnection> {
   226→    try {
   227→      logger.debug(`Getting completed cycles for team: ${teamId}`);
   228→      
   229→      const cycles = await this.client.cycles({
   230→        filter: {
   231→          team: { id: { eq: teamId } },
   232→        },
   233→        includeArchived: false,
   234→      });
   235→
   236→      const cycleNodes = await cycles.nodes;
   237→      
   238→      // Filter cycles that have a completedAt date
   239→      const completedCycles = cycleNodes.filter(cycle => cycle.completedAt);
   240→
   241→      // Return as connection format (simplified mock for now)
   242→      return {
   243→        ...cycles,
   244→        nodes: completedCycles,
   245→      } as CycleConnection;
   246→    } catch (error) {
   247→      logger.error(`Failed to get completed cycles for team ${teamId}`, error);
   248→      throw error;
   249→    }
   250→  }
   251→
   252→  async getIssues(cycleId: string, filter?: IssueFilter): Promise<IssueConnection> {
   253→    try {
   254→      logger.debug(`Getting issues for cycle: ${cycleId}`);
   255→      
   256→      const linearFilter: LinearIssueFilter = {
   257→        cycle: { id: { eq: cycleId } },
   258→      };
   259→      
   260→      if (filter) {
   261→        if (filter.state) {
   262→          linearFilter.state = { type: { eq: filter.state } };
   263→        }
   264→        if (filter.assigneeId) {
   265→          linearFilter.assignee = { id: { eq: filter.assigneeId } };
   266→        }
   267→      }
   268→
   269→      const issues = await this.client.issues({
   270→        filter: linearFilter,
   271→        includeArchived: false,
   272→      });
   273→
   274→      return issues;
   275→    } catch (error) {
   276→      logger.error(`Failed to get issues for cycle ${cycleId}`, error);
   277→      throw error;
   278→    }
   279→  }
   280→
   281→  async addIssue(cycleId: string, issueId: string): Promise<Issue> {
   282→    try {
   283→      logger.debug(`Adding issue ${issueId} to cycle ${cycleId}`);
   284→      
   285→      const issue = await this.client.issue(issueId);
   286→      if (!issue) {
   287→        throw new NotFoundError('Issue', issueId);
   288→      }
   289→
   290→      const payload = await this.client.updateIssue(issueId, {
   291→        cycleId: cycleId,
   292→      });
   293→
   294→      if (!payload.success || !payload.issue) {
   295→        throw new ValidationError('Failed to add issue to cycle');
   296→      }
