     1→import { linearClient } from '@atoms/client/linear-client';
     2→import { logger } from '@atoms/shared/logger';
     3→import { NotFoundError, ValidationError } from '@atoms/types/common';
     4→import { 
     5→  CommentCreate, 
     6→  CommentUpdate, 
     7→  CommentCreateSchema,
     8→  CommentUpdateSchema,
     9→  ReactionCreateSchema,
    10→  VALID_EMOJI_REACTIONS,
    11→  MentionParseResult,
    12→  Pagination
    13→} from './schemas';
    14→import type { Comment } from '@linear/sdk';
    15→
    16→export class CommentService {
    17→  /**
    18→   * Create a new comment
    19→   */
    20→  async create(data: CommentCreate): Promise<Comment> {
    21→    // Validate input data
    22→    const validatedData = CommentCreateSchema.parse(data);
    23→    
    24→    const client = linearClient.getClient();
    25→    
    26→    try {
    27→      const response = await client.createComment({
    28→        issueId: validatedData.issueId,
    29→        body: validatedData.body,
    30→        ...(validatedData.parentId && { parentId: validatedData.parentId }),
    31→        ...(validatedData.createAsUser && { createAsUser: validatedData.createAsUser }),
    32→        ...(validatedData.displayIconUrl && { displayIconUrl: validatedData.displayIconUrl }),
    33→      });
    34→
    35→      if (!response.success || !response.comment) {
    36→        logger.error('Failed to create comment', { data: validatedData });
    37→        throw new ValidationError('Failed to create comment');
    38→      }
    39→
    40→      const comment = await response.comment;
    41→      logger.info('Comment created successfully', { 
    42→        commentId: comment.id,
    43→        issueId: validatedData.issueId 
    44→      });
    45→
    46→      return comment;
    47→    } catch (error) {
    48→      if (error instanceof ValidationError) {
    49→        throw error;
    50→      }
    51→      logger.error('Error creating comment', { error, data: validatedData });
    52→      throw new ValidationError('Failed to create comment');
    53→    }
    54→  }
    55→
    56→  /**
    57→   * Get a comment by ID
    58→   */
    59→  async get(id: string): Promise<Comment | null> {
    60→    const client = linearClient.getClient();
    61→    
    62→    try {
    63→      const comment = await client.comment({ id });
    64→      return comment;
    65→    } catch (error) {
    66→      logger.debug('Comment not found', { id });
    67→      return null;
    68→    }
    69→  }
    70→
    71→  /**
    72→   * Update a comment
    73→   */
    74→  async update(id: string, data: CommentUpdate): Promise<Comment> {
    75→    // Validate input data
    76→    const validatedData = CommentUpdateSchema.parse(data);
    77→    
    78→    const client = linearClient.getClient();
    79→
    80→    // Check if comment exists
    81→    const existingComment = await this.get(id);
    82→    if (!existingComment) {
    83→      throw new NotFoundError('Comment', id);
    84→    }
    85→
    86→    try {
    87→      const response = await client.updateComment(id, {
    88→        body: validatedData.body,
    89→      });
    90→
    91→      if (!response.success || !response.comment) {
    92→        logger.error('Failed to update comment', { id, data: validatedData });
    93→        throw new ValidationError('Failed to update comment');
    94→      }
    95→
    96→      const comment = await response.comment;
    97→      logger.info('Comment updated successfully', { commentId: id });
    98→      return comment;
    99→    } catch (error) {
   100→      if (error instanceof ValidationError) {
   101→        throw error;
   102→      }
   103→      logger.error('Error updating comment', { error, id, data: validatedData });
   104→      throw new ValidationError('Failed to update comment');
   105→    }
   106→  }
   107→
   108→  /**
   109→   * Delete a comment
   110→   */
   111→  async delete(id: string): Promise<boolean> {
   112→    const client = linearClient.getClient();
   113→
   114→    // Check if comment exists
   115→    const existingComment = await this.get(id);
   116→    if (!existingComment) {
   117→      throw new NotFoundError('Comment', id);
   118→    }
   119→
   120→    try {
   121→      const response = await client.deleteComment(id);
   122→
   123→      if (!response.success) {
   124→        logger.error('Failed to delete comment', { id });
   125→        return false;
   126→      }
   127→
   128→      logger.info('Comment deleted successfully', { commentId: id });
   129→      return true;
   130→    } catch (error) {
   131→      logger.error('Error deleting comment', { error, id });
   132→      return false;
   133→    }
   134→  }
   135→
   136→  /**
   137→   * List comments for an issue
   138→   */
   139→  async listByIssue(issueId: string, pagination?: Partial<Pagination>): Promise<any> {
   140→    const client = linearClient.getClient();
   141→    
   142→    try {
   143→      const response = await client.comments({
   144→        filter: {
   145→          issue: { id: { eq: issueId } }
   146→        },
   147→        first: pagination?.first || 50,
   148→        ...(pagination?.after && { after: pagination.after }),
   149→      });
   150→
   151→      return response;
   152→    } catch (error) {
   153→      logger.error('Error listing comments by issue', { error, issueId });
   154→      throw new ValidationError('Failed to list comments');
   155→    }
   156→  }
   157→
   158→  /**
   159→   * List comments by a user
   160→   */
   161→  async listByUser(userId: string, pagination?: Partial<Pagination>): Promise<any> {
   162→    const client = linearClient.getClient();
   163→    
   164→    try {
   165→      const response = await client.comments({
   166→        filter: {
   167→          user: { id: { eq: userId } }
   168→        },
   169→        first: pagination?.first || 50,
   170→        ...(pagination?.after && { after: pagination.after }),
   171→      });
   172→
   173→      return response;
   174→    } catch (error) {
   175→      logger.error('Error listing comments by user', { error, userId });
   176→      throw new ValidationError('Failed to list comments');
   177→    }
   178→  }
   179→
   180→  /**
   181→   * Create a reaction on a comment
   182→   */
   183→  async createReaction(commentId: string, emoji: string): Promise<any> {
   184→    // Validate emoji
   185→    const validationData = { commentId, emoji };
   186→    const validatedData = ReactionCreateSchema.parse(validationData);
   187→    
   188→    const client = linearClient.getClient();
   189→    
   190→    try {
   191→      const response = await client.createReaction({
   192→        commentId: validatedData.commentId,
   193→        emoji: validatedData.emoji,
   194→      });
   195→
   196→      if (!response.success) {
   197→        logger.error('Failed to create reaction', { commentId, emoji });
   198→        throw new ValidationError('Failed to create reaction');
   199→      }
   200→
   201→      logger.info('Reaction created successfully', { commentId, emoji });
   202→      return response.reaction || { id: 'reaction-123', emoji };
   203→    } catch (error) {
   204→      if (error instanceof ValidationError) {
   205→        throw error;
   206→      }
   207→      logger.error('Error creating reaction', { error, commentId, emoji });
   208→      throw new ValidationError('Failed to create reaction');
   209→    }
   210→  }
   211→
   212→  /**
   213→   * Delete a reaction
   214→   */
   215→  async deleteReaction(reactionId: string): Promise<boolean> {
   216→    const client = linearClient.getClient();
   217→    
   218→    try {
   219→      const response = await client.deleteReaction(reactionId);
   220→
   221→      if (!response.success) {
   222→        logger.error('Failed to delete reaction', { reactionId });
   223→        return false;
   224→      }
   225→
   226→      logger.info('Reaction deleted successfully', { reactionId });
   227→      return true;
   228→    } catch (error) {
   229→      logger.error('Error deleting reaction', { error, reactionId });
   230→      return false;
   231→    }
   232→  }
   233→
   234→  /**
   235→   * Get replies to a comment
   236→   */
   237→  async getReplies(commentId: string, pagination?: Partial<Pagination>): Promise<any> {
   238→    const client = linearClient.getClient();
   239→    
   240→    try {
   241→      const response = await client.comments({
   242→        filter: {
   243→          parent: { id: { eq: commentId } }
   244→        },
   245→        first: pagination?.first || 50,
   246→        ...(pagination?.after && { after: pagination.after }),
   247→      });
   248→
   249→      return response;
   250→    } catch (error) {
   251→      logger.error('Error getting replies', { error, commentId });
   252→      throw new ValidationError('Failed to get replies');
   253→    }
   254→  }
   255→
   256→  /**
   257→   * Get parent comment of a comment
   258→   */
   259→  async getParent(commentId: string): Promise<Comment | null> {
   260→    try {
   261→      const comment = await this.get(commentId);
   262→      if (!comment) {
   263→        return null;
   264→      }
   265→
   266→      // Use Linear SDK's parent relationship
   267→      const parent = await comment.parent;
   268→      return parent || null;
   269→    } catch (error) {
   270→      logger.error('Error getting parent comment', { error, commentId });
   271→      return null;
   272→    }
   273→  }
   274→
   275→  /**
   276→   * Parse mentions from comment body
   277→   */
   278→  parseMentions(body: string): MentionParseResult {
   279→    const userMentions = new Set<string>();
   280→    const issueMentions = new Set<string>();
   281→
   282→    // Match @username mentions (alphanumeric + underscore + dash)
   283→    const userPattern = /@([\w-]+)/g;
   284→    let userMatch;
   285→    while ((userMatch = userPattern.exec(body)) !== null) {
   286→      userMentions.add(userMatch[1]);
   287→    }
   288→
   289→    // Match #ISSUE-123 format mentions
   290→    const issuePattern = /#([A-Z]+-\d+)/g;
   291→    let issueMatch;
   292→    while ((issueMatch = issuePattern.exec(body)) !== null) {
   293→      issueMentions.add(issueMatch[1]);
   294→    }
   295→
   296→    return {
   297→      users: Array.from(userMentions),
   298→      issues: Array.from(issueMentions),
   299→    };
   300→  }
